#!/usr/bin/env node
// Generate server/setup/embedded.ts from the template files.
//
// `scripts/repo-ci/` and `scripts/repo-skills/` remain the single source (#4 AC 11).
// This bakes them into a module so the server never reads `scripts/` at runtime —
// which would tie the container image's layout to the repo's.
//
//   npm run embed:templates          # regenerate
//   npm run embed:templates -- --check   # fail if stale (CI / verify)
//
// The generated file is committed: `npm run start` is `tsx server/index.ts` with no
// bundler, so nothing else would produce it.

import { readFileSync, writeFileSync, readdirSync, statSync } from "node:fs";
import { dirname, resolve, relative } from "node:path";
import { fileURLToPath } from "node:url";

const HERE = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(HERE, "..");
const OUT = resolve(ROOT, "server/setup/embedded.ts");

/**
 * Every file under `scripts/repo-ci/` and `scripts/repo-skills/`, keyed by path relative
 * to scripts/. Deliberately mirrors the directories rather than the subset the server
 * currently reads: `deploy.yml` is installer-only today (`INSTALL_DEPLOY_GATE=1`), and a
 * hand-maintained allow-list here is a second source of truth waiting to drift.
 */
function collect() {
  const files = {};
  for (const dir of ["repo-ci", "repo-skills"]) {
    walk(resolve(HERE, dir), (abs) => {
      files[relative(HERE, abs).split("\\").join("/")] = readFileSync(abs, "utf8");
    });
  }
  return files;
}

function walk(dir, visit) {
  for (const entry of readdirSync(dir).sort()) {
    const abs = resolve(dir, entry);
    if (statSync(abs).isDirectory()) walk(abs, visit);
    else visit(abs);
  }
}

function render(files) {
  const entries = Object.keys(files)
    .sort()
    .map((k) => `  ${JSON.stringify(k)}: ${JSON.stringify(files[k])},`)
    .join("\n");

  return `// GENERATED by scripts/embed-templates.mjs — DO NOT EDIT.
//
// Source of truth: scripts/repo-ci/ and scripts/repo-skills/ (#4 AC 11).
// Regenerate with \`npm run embed:templates\`; \`npm run verify\` fails if this is stale.

/** Template file contents, keyed by path relative to \`scripts/\`. */
export const EMBEDDED_TEMPLATES: Readonly<Record<string, string>> = Object.freeze({
${entries}
});
`;
}

const wanted = render(collect());

if (process.argv.includes("--check")) {
  let current = "";
  try {
    current = readFileSync(OUT, "utf8");
  } catch {
    /* missing counts as stale */
  }
  if (current !== wanted) {
    console.error(
      "embedded templates are stale.\n" +
        "  scripts/repo-ci/ or scripts/repo-skills/ changed without regenerating.\n" +
        "  fix: npm run embed:templates"
    );
    process.exit(1);
  }
  console.log("✓ embedded templates match scripts/");
} else {
  writeFileSync(OUT, wanted);
  console.log(`wrote ${relative(ROOT, OUT)} (${Object.keys(collect()).length} files)`);
}
